/**
 * Get a shuffled subset of questions, optionally filtered by section.
 */
export function getCISSPQuestions(opts: {
  sectionIds?: string[];
  count?: number;
}): CISSPQuestion[] {
  const sectionNameMap: Record<string, string> = {
    security_risk: 'Security & Risk Management',
    asset_security: 'Asset Security',
    security_architecture: 'Security Architecture & Engineering',
    comm_network: 'Communication & Network Security',
    iam: 'Identity & Access Management (IAM)',
    security_assessment: 'Security Assessment & Testing',
    security_operations: 'Security Operations',
    software_security: 'Software Development Security',
  };

  let pool = [...CISSP_QUESTIONS];

  if (opts.sectionIds && opts.sectionIds.length > 0) {
    const sectionNames = new Set(opts.sectionIds.map(id => sectionNameMap[id]).filter(Boolean));
    pool = pool.filter(q => sectionNames.has(q.section));
  }

  // Shuffle
  for (let i = pool.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [pool[i], pool[j]] = [pool[j], pool[i]];
  }

  return pool.slice(0, opts.count || 20);
}
